import collections

class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_i] > self.rank[root_j]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1
            return True
        return False

def smallest_string_with_swaps(s: str, pairs: list[list[int]]) -> str:
    n = len(s)
    uf = UnionFind(n)

    for u, v in pairs:
        uf.union(u, v)

    components = collections.defaultdict(list)
    for i in range(n):
        root = uf.find(i)
        components[root].append((s[i], i))

    result_list = [''] * n

    for root in components:
        component_data = components[root]

        chars = [item[0] for item in component_data]
        indices = [item[1] for item in component_data]

        chars.sort()
        indices.sort()

        for i in range(len(chars)):
            result_list[indices[i]] = chars[i]

    return "".join(result_list)
